mapper.sql:
SELECT /*+ LEADING(B A) */ objid, stext, cmmn_cd_nm, cmmn_cd, sort_ordr FROM ( SELECT objid, stext FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND objid IN ( SELECT upobj FROM (
) GROUP BY upobj ) AND parts = '1' AND depth = '2' ) A LEFT JOIN ( SELECT REPLACE(cmmn_cd_nm, '영섬', '영·섬') AS cmmn_cd_nm, cmmn_cd, usr_dfn_vu1, usr_dfn_vu2, sort_ordr FROM tc_ecs_cd WHERE cls_cd = 'ECS_1000' ) B ON
A.objid = B.usr_dfn_vu2 WHERE cmmn_cd_nm IS NOT NULL

SELECT /*+ LEADING(A B) */ A.objid, A.stext, A.upobj, A.kostl, A.seqno, NVL(B.cmmn_cd_nm, '금강') AS cmmn_cd_nm, NVL(B.cmmn_cd, '02') AS cmmn_cd, NVL(B.sort_ordr, 2) AS sort_ordr FROM ( SELECT objid, stext, DECODE(upobj, '10690002', '20060557', '50013977', '20060557', '50029610', '10990028', upobj) AS upobj, kostl, seqno FROM (
) ) A, (
) B WHERE A.upobj = B.objid(+)

mapper.select:
/* CMMN_SQL_Dao_retrieveHRMDeptList */ WITH HRM_DEPT_LIST AS ( SELECT /*+ MATERIALZE */ objid, stext, upobj, kostl, kostx, seqno FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND objid IN ( SELECT DISTINCT CASE WHEN MIN(depth) OVER(PARTITION BY kostl) = depth THEN objid ELSE NULL END FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND TRIM(kostl) IS NOT NULL ) ) SELECT cls_cd, cls_cd_nm, cmmn_cd, cmmn_cd_nm, upper_cmmn_cd, empno FROM ( SELECT 'dept' AS cls_cd, '지사부서' AS cls_cd_nm, objid AS cmmn_cd, stext AS cmmn_cd_nm, kostl AS upper_cmmn_cd, '' AS empno FROM (
SELECT /*+ LEADING(A B) */ A.objid, A.stext, A.upobj, A.kostl, A.seqno, NVL(B.cmmn_cd_nm, '금강') AS cmmn_cd_nm, NVL(B.cmmn_cd, '02') AS cmmn_cd, NVL(B.sort_ordr, 2) AS sort_ordr FROM ( SELECT objid, stext, DECODE(upobj, '10690002', '20060557', '50013977', '20060557', '50029610', '10990028', upobj) AS upobj, kostl, seqno FROM (
SELECT objid, stext, upobj, kostl, kostx, seqno FROM HRM_DEPT_LIST
) ) A, (
) B WHERE A.upobj = B.objid(+) ORDER BY seqno ) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
ORDER BY cmmn_cd_nm )
UNION ALL SELECT /*+ LEADING(B A) */ 'dsuseDept' AS cls_cd, '폐기부서' AS cls_cd_nm, A.dept_id AS cmmn_cd, '[폐기] ' || A.dept_name AS cmmn_cd_nm, A.par_id AS upper_cmmn_cd, B.emp_code AS empno FROM ( SELECT dept_id, dept_name, par_id, seq AS seqno, LEVEL AS depth FROM DBLINKUSR.v_dept_global_ecs CONNECT BY PRIOR dept_id = par_id START WITH dept_id = '000000101' ORDER SIBLINGS BY seq ) A, ( SELECT dept_id, emp_code FROM DBLINKUSR.v_usr_global_ecs WHERE name LIKE '%_폐기%' ) B WHERE A.dept_id = B.dept_id

/* CMMN_SQL_Dao_retrieveHRMUserList */ SELECT dept, posit, grade, korname, empno FROM HRM.vm_hr01601 WHERE 1 = 1
AND korname like '%' || #{usrNm} || '%'
AND objid = #{ecsChrgDeptId}
ORDER BY boncd, /* 유역(HADE) */ objid, /* 지사(DEPT) */ timcd, /* 부서(sect) */ /* kwacd, -- 팀(team) */ calcd /* 직급(posit) */

/* CMMN_SQL_Dao_retrieveOasisElctrnDocHRMUser */ WITH HRM_USR_LIST AS ( SELECT /*+ MATERIALZE */ empno, dept, objid FROM HRM.vm_hr01601 WHERE 1 = 1
AND korname = #{usrNm}
ORDER BY empno DESC ) SELECT CASE WHEN ( SELECT COUNT(empno) FROM HRM_USR_LIST WHERE 1 = 1
AND dept = #{deptNm}
AND objid = #{ecsChrgDeptId}
AND empno < 30000000 ) > 0 THEN ( SELECT MAX(empno) FROM HRM_USR_LIST WHERE 1 = 1
AND dept = #{deptNm}
AND objid = #{ecsChrgDeptId}
AND empno < 30000000 ) WHEN ( SELECT COUNT(empno) FROM HRM_USR_LIST WHERE 1 = 1
AND dept = #{deptNm}
AND objid = #{ecsChrgDeptId}
) > 0 THEN ( SELECT MAX(empno) FROM HRM_USR_LIST WHERE 1 = 1
AND dept = #{deptNm}
AND objid = #{ecsChrgDeptId}
) WHEN ( SELECT COUNT(empno) FROM HRM_USR_LIST WHERE empno < 30000000 ) > 0 THEN ( SELECT MAX(empno) FROM HRM_USR_LIST WHERE empno < 30000000 ) ELSE ( SELECT MAX(empno) FROM HRM_USR_LIST ) END AS empno FROM dual

/* CMMN_SQL_Dao_retrieveOasisElctrnDocHRMDept */ WITH OASIS_DEPT AS ( SELECT /*+ MATERIALZE */ dept_id, dept_name, par_id, seq, LEVEL AS depth FROM DBLINKUSR.v_dept_global_ecs WHERE 1 = 1 AND dept_id NOT IN ( SELECT dept_id FROM DBLINKUSR.v_usr_global_ecs WHERE name LIKE '%_폐기%' ) CONNECT BY PRIOR dept_id = par_id START WITH dept_id = '000000101' ORDER SIBLINGS BY seq ), HRM_DEPT AS ( SELECT /*+ MATERIALZE */ objid, stext, depth, upobj, kostl, kostx, seqno FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt ) SELECT /*+ LEADING(A B) */ A.dept_id AS oasis_dept_id, A.dept_name AS oasis_dept_nm, A.seq AS oasis_seq, A.depth AS oasis_depth, A.par_id AS oasis_upp_dept_id, A.par_dept_name AS oasis_up_dept_nm, B.objid AS hrm_dept_id, B.stext AS hrm_dept_nm, B.depth AS hrm_depth, B.upstext AS hrm_up_dept_nm FROM ( SELECT dept_id, dept_name, par_id, seq, DECODE(dept_name, '인재개발원', depth + 1, depth) AS depth, DECODE(dept_name, '인재개발원', '인재개발원', ( SELECT REPLACE(REPLACE(dept_name, '사장직할', '사장직속'), '감사직할', '상임감사위원직속') FROM OASIS_DEPT WHERE dept_id = A.par_id )) AS par_dept_name FROM OASIS_DEPT A WHERE 1 = 1
AND dept_id = #{ecsChrgDeptId}
) A, ( SELECT objid, stext, depth, ( SELECT stext FROM HRM_DEPT WHERE objid = A.upobj ) AS upstext FROM HRM_DEPT A WHERE objid IN ( SELECT DISTINCT CASE WHEN MIN(depth) OVER(PARTITION BY kostl) = depth THEN objid ELSE NULL END FROM HRM_DEPT WHERE TRIM(kostl) IS NOT NULL ) ) B WHERE A.dept_name = B.stext AND A.depth = B.depth AND A.par_dept_name = B.upstext ORDER BY hrm_dept_nm

/* CMMN_SQL_Dao_retrieveSetcscList */ SELECT cls_cd, cmmn_cd, cmmn_cd_nm, usr_dfn_vu2 AS elcpwstn_cls_cd, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1001' AND usr_dfn_vu3 LIKE '%' || #{cnd} || '%'
UNION ALL SELECT '' AS cls_cd, '99' AS cmmn_cd, '해당없음' AS cmmn_cd_nm, '' AS elcpwstn_cls_cd, 99 AS sort_ordr FROM dual
ORDER BY sort_ordr

/* CMMN_SQL_Dao_retrieveDeptMappingList */ SELECT 'deptMapping' AS cls_cd, '부서코드' AS cls_cd_nm, cmmn_cd, cmmn_cd_nm, upper_cmmn_cd, ( SELECT cmmn_cd_nm FROM (
) WHERE objid = ) AS upper_cmmn_cd_nm FROM ( SELECT 'deptMapping' AS cls_cd, '부서코드' AS cls_cd_nm, objid AS cmmn_cd, stext AS cmmn_cd_nm, upobj AS upper_cmmn_cd FROM (
) WHERE upobj IN ( SELECT objid FROM (
) ) ORDER BY seqno ) ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrieveBplcList */ SELECT cls_cd, cls_cd_nm, cmmn_cd, cmmn_cd_nm, upper_cmmn_cd, upper_cmmn_cd_nm, upper_cmmn_cd2, upper_cmmn_cd_nm2 FROM ( SELECT A.cls_cd, ( SELECT cls_cd_nm FROM tc_ecs_cls_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2002' ) AS cls_cd_nm, A.cmmn_cd, A.cmmn_cd_nm, ( SELECT cmmn_cd FROM tc_ecs_cd WHERE cls_cd = ( SELECT upper_cls_cd FROM tc_ecs_cd WHERE cls_cd = A.upper_cls_cd AND cmmn_cd = A.upper_cmmn_cd ) AND cmmn_cd = ( SELECT upper_cmmn_cd FROM tc_ecs_cd WHERE cls_cd = A.upper_cls_cd AND cmmn_cd = A.upper_cmmn_cd ) ) AS upper_cmmn_cd, ( SELECT cmmn_cd_nm FROM tc_ecs_cd WHERE cls_cd = ( SELECT upper_cls_cd FROM tc_ecs_cd WHERE cls_cd = A.upper_cls_cd AND cmmn_cd = A.upper_cmmn_cd ) AND cmmn_cd = ( SELECT upper_cmmn_cd FROM tc_ecs_cd WHERE cls_cd = A.upper_cls_cd AND cmmn_cd = A.upper_cmmn_cd ) ) AS upper_cmmn_cd_nm, upper_cmmn_cd AS upper_cmmn_cd2, ( SELECT cmmn_cd_nm FROM tc_ecs_cd WHERE cls_cd = A.upper_cls_cd AND cmmn_cd = A.upper_cmmn_cd ) AS upper_cmmn_cd_nm2 FROM tc_ecs_cd A WHERE A.use_yn = 'Y' AND A.cls_cd = 'ECS_2002' ORDER BY A.sort_ordr ) WHERE 1 = 1
AND upper_cmmn_cd = #{ecsBasinDivCd}
AND upper_cmmn_cd2 = #{ecsChrgDeptId}
ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrieveCnsmpCndDeptList */ SELECT 'GHGDeptMapping' AS cls_cd, 'GHG부서코드' AS cls_cd_nm, cmmn_cd, cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE use_yn = 'Y' AND cls_cd LIKE 'GHG_1002' AND cmmn_cd != '88888889' /* 위탁 */ AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrieveCnstscList */ SELECT /*+ LEADING(A B) */ A.cmmn_cd, A.cmmn_cd_nm, B.cmmn_cd AS cmmn_cd1, B.cmmn_cd_nm AS cmmn_cd_nm1 FROM ( SELECT cmmn_cd, usr_dfn_vu2, cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1003' ) A, ( SELECT cmmn_cd, cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE use_yn = 'Y' AND cls_cd = 'GHG_0024' ) B WHERE A.usr_dfn_vu2 = B.cmmn_cd
AND usr_dfn_vu2 IN
#{item}

/* CMMN_SQL_Dao_retrieveWtwkEltengMsrinsCndDeptList */ SELECT 'WtwkEltengMsrinsDept' AS cls_cd, '수전전력량계부서코드' AS cls_cd_nm, objid AS cmmn_cd, stext AS cmmn_cd_nm FROM ( SELECT objid, stext, seqno FROM (
) UNION ALL SELECT objid, stext, seqno FROM (
) UNION ALL SELECT objid, stext, seqno FROM HRM.VM_HR01A01 WHERE SYSDATE BETWEEN strdt AND enddt AND stext = '본사' ORDER BY seqno ) ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrievePrdctnCndDeptList */ SELECT 'WRODeptMapping' AS cls_cd, 'WRO부서코드' AS cls_cd_nm, cmmn_cd, cmmn_cd_nm, ( SELECT objid FROM (
) WHERE objid = elcpwstn_mnggrp_dept_cd
GROUP BY objid ) AS objid, hq_cd AS upper_cmmn_cd, ( SELECT cmmn_cd_nm FROM (
) WHERE objid = hq_cd ) AS upper_cmmn_cd_nm FROM ( SELECT cstct_vu AS cmmn_cd, ( SELECT stext FROM (
) WHERE kostl = LPAD(cstct_vu, 10, '0') ) AS cmmn_cd_nm, MAX(elcpwstn_mnggrp_dept_cd) AS elcpwstn_mnggrp_dept_cd, MAX() AS hq_cd, MAX(dsply_ordr) AS dsply_ordr FROM WRO.tc_eg10101 WHERE /* centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' */ accnut_lnk_elcpwstn_yn = 'Y' AND elcpwstn_div_cd != 'X' AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND cstct_vu = #{ecsChrgDeptId}
GROUP BY cstct_vu ) ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrievePrdctnCndSetcscList */ SELECT 'WROElcpwstnMapping' AS cls_cd, 'WRO발전소코드' AS cls_cd_nm, cmmn_cd, cmmn_cd_nm, hq_cd AS upper_cmmn_cd, ( SELECT cmmn_cd_nm FROM (
) WHERE objid = hq_cd ) AS upper_cmmn_cd_nm, elcpwstn_cls_cd AS upper_cmmn_cd2, ( SELECT cmmn_cd_nm FROM (
) B WHERE B.elcpwstn_cls_cd LIKE '%' || A.elcpwstn_cls_cd || '%'
AND B.cnd LIKE '%' || #{cnd1} || '%'
AND ROWNUM = 1 ) AS upper_cmmn_cd_nm2, cstct_vu AS upper_cmmn_cd3, cstct_nm AS upper_cmmn_cd_nm3 FROM ( SELECT cmmn_cd, cmmn_cd_nm, hq_cd, elcpwstn_cls_cd, cstct_vu, ( SELECT stext FROM (
) WHERE kostl = LPAD(cstct_vu, 10, '0') ) AS cstct_nm FROM ( SELECT elcpwstn_cd AS cmmn_cd, MAX(elcpwstn_nm) AS cmmn_cd_nm, MAX(hq_cd) AS hq_cd, MAX(elcpwstn_cls_cd) AS elcpwstn_cls_cd, MAX(cstct_vu) AS cstct_vu, MAX(cstct_nm) AS cstct_nm FROM WRO.tc_eg10101 WHERE centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' /* elcpwstn_div_cd != 'X' AND accnut_lnk_elcpwstn_yn = 'Y' */ AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cnd LIKE '%' || #{cnd1} || '%'
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND cstct_vu = #{ecsChrgDeptId}
GROUP BY elcpwstn_cd ORDER BY MAX(dsply_ordr) )
/* 한전거래 태양광 */ UNION ALL SELECT cmmn_cd, cmmn_cd_nm, hq_cd, elcpwstn_cls_cd, cstct_vu, ( SELECT stext FROM (
) WHERE kostl = LPAD(cstct_vu, 10, '0') ) AS cstct_nm FROM ( SELECT elcpwstn_cd AS cmmn_cd, MAX(elcpwstn_nm) AS cmmn_cd_nm, MAX(hq_cd) AS hq_cd, MAX(elcpwstn_cls_cd) AS elcpwstn_cls_cd, MAX(cstct_vu) AS cstct_vu, MAX(cstct_nm) AS cstct_nm FROM WRO.tc_eg10101 WHERE elcpwstn_cls_cd = '0005' AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cnd LIKE '%' || #{cnd1} || '%'
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND cstct_vu = #{ecsChrgDeptId}
GROUP BY elcpwstn_cd ORDER BY MAX(dsply_ordr) )
) A ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrieveCnsmpSttusCndKepcoDeptList */ SELECT 'kepcoDept' AS cls_cd, '한전부서코드' AS cls_cd_nm, cmmn_cd, cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2001'
AND upper_cmmn_cd = #{ecsBasinDivCd}
ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrieveInhouseSnpwDeptList */ SELECT 'inhouseSnpw' AS cls_cd, '소내태양광' AS cls_cd_nm,
dept_cd AS cmmn_cd, MAX(dept_nm) AS cmmn_cd_nm, MAX(basin_cd) AS upper_cmmn_cd, MAX(basin_nm) AS upper_cmmn_cd_nm
bplc_cd AS cmmn_cd, MAX(bplc_nm) AS cmmn_cd_nm, MAX(dept_cd) AS upper_cmmn_cd, MAX(dept_nm) AS upper_cmmn_cd_nm, MAX(inhouse_cnsmp_eqp_cpcty) AS upper_cmmn_cd2
FROM ( SELECT /*+ LEADING(BASIN DEPT BPLC USWTR_SQTY INHOUSE_CNSMP_SNPW) */ BASIN.cmmn_cd AS basin_cd, BASIN.cmmn_cd_nm AS basin_nm, BASIN.sort_ordr AS basin_sort, DEPT.cmmn_cd AS dept_cd, DEPT.cmmn_cd_nm AS dept_nm, DEPT.sort_ordr AS dept_sort, BPLC.cmmn_cd AS bplc_cd, BPLC.cmmn_cd_nm AS bplc_nm, BPLC.sort_ordr AS bplc_sort, INHOUSE_CNSMP_SNPW.cmmn_cd AS inhouse_cnsmp_snpw_cd, INHOUSE_CNSMP_SNPW.cmmn_cd_nm AS inhouse_cnsmp_snpw_cd_nm, INHOUSE_CNSMP_SNPW.usr_dfn_vu1 AS inhouse_cnsmp_eqp_cpcty, INHOUSE_CNSMP_SNPW.sort_ordr AS inhouse_cnsmp_snpw_cd_sort FROM ( SELECT cls_cd, cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1000' ) BASIN, ( SELECT cls_cd, cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2001' ) DEPT, ( SELECT cls_cd, cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, usr_dfn_vu1, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2002' ) BPLC, ( SELECT cls_cd, cmmn_cd, cmmn_cd_nm, upper_cls_cd, upper_cmmn_cd, usr_dfn_vu1, sort_ordr FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2011' ) INHOUSE_CNSMP_SNPW WHERE INHOUSE_CNSMP_SNPW.upper_cls_cd = BPLC.cls_cd AND INHOUSE_CNSMP_SNPW.upper_cmmn_cd = BPLC.cmmn_cd AND BPLC.upper_cls_cd = DEPT.cls_cd AND BPLC.upper_cmmn_cd = DEPT.cmmn_cd AND DEPT.upper_cls_cd = BASIN.cls_cd AND DEPT.upper_cmmn_cd = BASIN.cmmn_cd
AND BASIN.cmmn_cd = #{ecsBasinDivCd}
AND DEPT.cmmn_cd = #{ecsChrgDeptId}
ORDER BY basin_sort, dept_sort, bplc_sort, inhouse_cnsmp_snpw_cd_sort ) GROUP BY
dept_cd
bplc_cd
ORDER BY cmmn_cd_nm

/* CMMN_SQL_Dao_retrieveRecCndSetcscList */ SELECT 'recSetcsc' AS cls_cd, 'REC발전원코드' AS cls_cd_nm, cmmn_cd, cmmn_cd_nm, hq_cd AS upper_cmmn_cd, ( SELECT cmmn_cd_nm FROM (
) WHERE objid = hq_cd ) AS upper_cmmn_cd_nm, elcpwstn_cls_cd AS upper_cmmn_cd2, ( SELECT cmmn_cd_nm FROM (
) B WHERE B.elcpwstn_cls_cd LIKE '%' || A.elcpwstn_cls_cd || '%' AND cnd LIKE '%02%' AND ROWNUM = 1 ) AS upper_cmmn_cd_nm2, cstct_vu AS upper_cmmn_cd3, ( SELECT stext FROM (
) WHERE kostl = LPAD(cstct_vu, 10, '0') ) AS upper_cmmn_cd_nm3 FROM (
) A ORDER BY cmmn_cd_nm
